                var currentActivity = this;
                Java.scheduleOnMainThread(function () {
                    var pinEditText = currentActivity.findViewById(0x7f0a0001); // Replace with actual R.id.pin_edit_text
                    if (pinEditText !== null) {
                        console.log("[Frida] Found PIN EditText:", pinEditText);
                        var textWatcher = Java.registerClass({
                            name: 'com.huawei.digitalpayment.PinTextWatcher',
                            implements: [Java.use('android.text.TextWatcher')],
                            methods: {
                                beforeTextChanged: function (s, start, count, after) {},
                                onTextChanged: function (s, start, before, count) {
                                    console.log("[Frida] PIN input changed: " + s.toString());
                                },
                                afterTextChanged: function (s) {
                                    console.log("[Frida] PIN final value (afterTextChanged): " + s.toString());
                                }
                            }
                        });
                        pinEditText.addTextChangedListener(textWatcher.$new());
                        console.log("[Frida] Hooked PIN EditText for text changes.");

                        // Also hook the button that submits the PIN, if available
                        // e.g., var submitButton = currentActivity.findViewById(0x7f0a0002);
                        // if (submitButton !== null) {
                        //     submitButton.setOnClickListener(Java.use('android.view.View$OnClickListener').$new({
                        //         onClick: function(v) {
                        //             console.log("[Frida] Submit button clicked! Final PIN:", pinEditText.getText().toString());
                        //             // Call original click listener
                        //             // if (submitButton.getOnClickListener() !== null) { ... }
